import{_ as t,o as n,c as i,a3 as a}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"14. Statewide Industry Panel","description":"","frontmatter":{"title":"14. Statewide Industry Panel","eba":"Nurses and Midwives 2024-2028","topics":["consultation","disputes","discipline","classifications"]},"headers":[],"relativePath":"ebas/nurses-midwives/consultation-disputes/14-statewide-industry-panel.md","filePath":"ebas/nurses-midwives/consultation-disputes/14-statewide-industry-panel.md"}'),o={name:"ebas/nurses-midwives/consultation-disputes/14-statewide-industry-panel.md"};function s(r,e,p,l,d,h){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_14-statewide-industry-panel" tabindex="-1">14. Statewide Industry Panel <a class="header-anchor" href="#_14-statewide-industry-panel" aria-label="Permalink to &quot;14. Statewide Industry Panel&quot;">​</a></h1><p><strong>14.1</strong> Application</p><p>The Statewide Industry Panel (Panel) can undertake the following functions:</p><p><strong>(a)</strong> Determine applications regarding classifications where:</p><p><strong>(i)</strong> an Employee&#39;s position or the position the Employer proposes to create is not subject to an existing classification in the Agreement or previous determination of the Statewide Classification Committee (see clause 14.3);</p><p><strong>(ii)</strong> there is a dispute about an existing classification under this Agreement (see clause 14.4) which may include the categorisation of the Campus or health service;</p><p><strong>(b)</strong> Determine disputes that arise under <a href="/eba/ebas/nurses-midwives/consultation-disputes/11B-no-amalgamation-of-wards-without-agreement-of-anmf-and.html">clause 11B</a> (No amalgamation of wards without agreement of the Unions and Employer);</p><p><strong>(c)</strong> Resolve disputes about the relevance of a qualification as it applies to a qualification allowance or Clinical Nurse Specialist/Clinical Midwife Specialist eligibility;</p><p><strong>(d)</strong> Resolve a dispute regarding a digital supplementary roster that cannot be resolved at the Central Implementation Committee; and/or</p><p><strong>(e)</strong> Resolve a dispute in accordance with <a href="/eba/ebas/nurses-midwives/safe-patient-care/107-midwifery-continuity-of-care-models.html">clause 107.7A</a>.</p><p><strong>14.2</strong> Panel</p><p><strong>(a)</strong> The Panel will comprise three persons being:</p><p><strong>(i)</strong> a nominee of the VHIA (on behalf of the Employers);</p><p><strong>(ii)</strong> a nominee of the ANMF (on behalf of the Employees); and</p><p><strong>(iii)</strong> an independent chairperson agreed by VHIA and the ANMF or, in the absence of agreement, as nominated by the Minister for Health.</p><p><strong>(c)</strong> The Panel will commence to determine the matter within 21 days of the application and conclude its deliberations within a further 21 days.</p><p><strong>(d)</strong> No nominee on the Panel may be involved in a matter if they are directly affected by or are personally interested in the outcome.</p><p><strong>(e)</strong> The Panel shall act independently of the VHIA and the ANMF.</p><p><strong>(f)</strong> The Panel Chairperson shall act as an independent third party in deliberations of the Panel.</p><p><strong>(g)</strong> The Parties to an application to the Panel bear their own costs (save for the chairperson).</p><p><strong>(h)</strong> The Panel shall be responsible for determining its own procedure, provided that the procedure shall be consistent with the requirements of this clause 14, and shall adopt an inquisitorial procedure (rather than an adversarial procedure).</p><p><strong>14.3</strong> Application to Panel where not subject to an existing classification</p><p><strong>(a)</strong> Where the circumstances in subclause 14.1(a)(i) arise, a written notification to the Panel will be made as follows:</p><p><strong>(i)</strong> By the Employer within 14 days of the matter arising under subclause 14.1(a)(i);</p><p><strong>(ii)</strong> By the Employee and/or their representative (such as the ANMF) where:</p><p><strong>(A)</strong> the Employer has been notified in writing of the intention to make an application to the Panel;</p><p><strong>(B)</strong> 28 days have elapsed since that written notification without the Employer having made an application to the Panel in relation to the identified position/s;</p><p><strong>(C)</strong> the Employer and the Employee (and the Employee’s representative) have met and discussed the proposed application and the outcome of the discussion confirmed in writing; and</p><p><strong>(D)</strong> the Employer and Employee (and their representatives where relevant) have cooperated to ensure a meeting occurs within 28 days of subclause 14.3(a)(ii)(A).</p><p><strong>(iii)</strong> Where an Employer fails to cooperate and meet as required at subclauses 14.3(a)(ii)(C) or (ii)(D), this does not prevent an Employee making an application to the Panel.</p><p><strong>(iv)</strong> Where an Employee (or representative) fails to cooperate and meet as required at subclauses 14.3(a)(ii)(C) or (ii)(D), this will result in the Panel not dealing with the application until that meeting occurs.</p><p><strong>(b)</strong> Where an application is received, the Chairperson will notify the applicable Union/s and VHIA in writing.</p><p><strong>14.4</strong> Application to Panel where there is a dispute regarding an existing classification</p><p><strong>(a)</strong> Either an Employer or an Employee (or their representatives) may make an application to the Panel regarding a dispute about an Employee’s classification where the Parties have attempted to resolve the dispute at the workplace as described at <a href="/eba/ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.html">clause 13.4</a> and met the obligations set out at <a href="/eba/ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.html">clause 13.2</a>.</p><p><strong>(b)</strong> Where an application is made to the Panel the terms of <a href="/eba/ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.html">clause 13.2</a> continue to apply.</p><p><strong>(c)</strong> An Employee who is a Party to the dispute will be released by the Employer from normal duties as is reasonably necessary to enable them to participate in this dispute settling procedure so long as it does not unduly affect the operations of the Employer.</p><p><strong>14.5</strong> Materials to be provided to the Panel for classification applications</p><p>Where an application to the Panel is made under clauses 14.3 or 14.4:</p><p><strong>(a)</strong> the Employer will provide the following materials (where available) as soon as practicable:</p><p><strong>(i)</strong> the position description of the role;</p><p><strong>(ii)</strong> mandatory and desirable post-registration skills, knowledge and education;</p><p><strong>(iii)</strong> the grade proposed by the applicant and the comparator position/s used to determine the proposed grade;</p><p><strong>(iv)</strong> proposed and/or actual professional reporting lines for/to the proposed position/s;</p><p><strong>(v)</strong> outline of the existing and proposed organisational structure applicable to the position/s; and</p><p><strong>(vi)</strong> identification of EFT and skill mix (if any) that reports to the position/s; and</p><p><strong>(b)</strong> Where the application concerns an existing Employee, the Employer will ensure the Employee is given the opportunity to provide:</p><p><strong>(i)</strong> an outline of the skill, duties, responsibilities and educational underpinning of the role;</p><p><strong>(ii)</strong> objective observations on any differences between the role and that described in the position description; and</p><p><strong>(iii)</strong> the Employer&#39;s response, if any, to the existing Employee&#39;s outline at subclauses 14.5(b)(i) and (ii).</p><p><strong>14.6</strong> Role of the Panel in considering an application</p><p><strong>(a)</strong> In considering an application, the Panel will:</p><p><strong>(i)</strong> in the case of an application under clause 14.3, utilise available research-based skill matrices and other relevant material;</p><p><strong>(ii)</strong> in the case of an application under clauses 14.3 or 14.4, determine classification applications by the inherent requirements of the position, not those of the individual;</p><p><strong>(iii)</strong> in the case of an application under clause 14.4, apply the classification descriptors of the Agreement;</p><p><strong>(iv)</strong> in the case of an application under subclause 14.1(b), have regard to the DOH&#39;s Guidelines which will reflect historical and contemporary practice standards; and</p><p><strong>(v)</strong> in the case of an application under subclause 14.1(a) or (b), consider any materials submitted by or on behalf of the DOH.</p><p><strong>(b)</strong> The Panel may otherwise inform itself in any manner it sees fit including, in the case of a classification application under clause 14.3 or 14.4, by seeking the views of an expert advisor (who is not an Employee of the health service subject of the application) agreed to by the Panel to provide clinical expertise in an area of nursing or midwifery practice in relation to the classification matter under consideration.</p><p><strong>(c)</strong> The Employer or VHIA and the Employee/s and/or the ANMF can advocate to the Panel.</p><p><strong>(d)</strong> The Panel will determine applications by majority, with written reasons to be prepared by the Chairperson (including any dissenting decision or a summary of any dissenting decision) and provided to the parties. In the case of an application under clauses 14.3 or 14.4, the Panel may determine to support the re-grading or substitute a different grade to the role.</p><p><strong>(e)</strong> A determination of the Panel will be considered binding unless either the Unions or VHIA make an application to have the determination reviewed by the Commission within 14 days of receiving written determination. For the avoidance of doubt, no activity under clause 14.9 constitutes a determination for the purposes of subclause 14.6(e).</p><p><strong>(f)</strong> An application to the Commission will include the application, determination, written reasons and supporting material.</p><p><strong>(g)</strong> On receipt of an application under this clause, the President of the Commission will appoint a member of the Commission to preside over the matter.</p><p><strong>(h)</strong> The Commission will be assisted by the Chairperson, who will explain their recommendation, the application and supporting material, and inform the Commission of the position of the ANMF and the VHIA.</p><p><strong>(i)</strong> The Commission will adopt an inquisitorial procedure (rather than an adversarial procedure) and will in effect stand in the shoes of the Panel and determine whether the Panel decision under review was properly reached, and may substitute or uphold the existing determination. Any determination under this clause will be final and binding upon the parties and will not be subject to an appeal of the Full Bench.</p><p><strong>14.7</strong> Additional role of the Chairperson in considering matters affecting a hospital/health service&#39;s funding</p><p><strong>(a)</strong> The ANMF and VHIA recognise that the Victorian Government, represented by the DOH, has an implied right to have its interests heard and considered in decisions of the Panel.</p><p><strong>(b)</strong> If a matter before the Panel under subclauses 14.1(a) or (b) may result in a requirement for additional funding to a hospital or health service (beyond what is currently provided under regular State budget mechanisms), the Chairperson will ensure that:</p><p><strong>(i)</strong> the DOH has a fair opportunity to be heard by the Panel; and</p><p><strong>(ii)</strong> the DOH&#39;s interests are given due consideration by the Panel in its decision-making.</p><p><strong>14.8</strong> Panel determinations</p><p><strong>(a)</strong> The Panel will notify the Employer (and Employee where applicable) of the outcome of the application in writing within 14 days of the decision.</p><p><strong>(b)</strong> In the case of an application under subclause 14.1(a), the determined grade will apply from the date of the application or a later date determined by the Panel.</p><p><strong>(c)</strong> Until the determination of the Panel, the existing grade (where relevant) will continue to apply.</p><p><strong>(d)</strong> In the case of an application under clause 14.3, where the Panel or, on review, the Commission determines that a lower classification applies, the Employee will have their current salary maintained.</p><p><strong>14.9</strong> Development and finalisation of Classification descriptors</p><p>The classification work referred to in subclauses 14.9(a)(ii) and (iii) of the 2020 Agreement will be finalised in accordance with clause 14.9 of the 2020 Agreement.</p>',76)])])}const u=t(o,[["render",s]]);export{g as __pageData,u as default};
